package com.indianhive.web.ordering.repository;import com.indianhive.web.ordering.entity.orderItemEntity;import org.springframework.data.jpa.repository.JpaRepository;import org.springframework.stereotype.Repository;import java.util.List;@Repositorypublic interface orderItemRepository extends JpaRepository<orderItemEntity, Long> {    List<orderItemEntity> findByOrderId(Long orderId);    List<orderItemEntity> findByDishId(Long dishId);    void deleteByOrderId(Long orderId);    Long countByOrderId(Long orderId);    boolean existsByOrderIdAndDishId(Long orderId, Long dishId);}